INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-d592fc58-moex-00117', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '某甲因意外事故四肢受創嚴重，於病床前指定三人以上之見證人，口述遺囑意旨，使見證人中之 一人筆記、宣讀、講解。某甲認可後，記明年、月、日及代筆人之姓名，由見證人全體簽名，某 甲因雙手傷重，無法簽名以印章代之。該代筆遺囑之效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00118', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲在網站上，看到乙欲出賣一幅名畫，便在某年7月3日上午寄信給乙，表示願意依標價購買， 該信件在同年7月6日送達，惟甲在同年7月5日因意外事故死亡，甲所為購買名畫之意思表示 效力如何？', '["無效", "有效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00119', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '關於代理，下列敘述何者錯誤？', '["純粹之身分行為不得代理，但得藉由使者傳達該身分行為之意思表示", "代表之法律效果多類推適用代理之法理，而兩者之區別在於前者之效果當然歸屬於被代表人， 後者則於符合代理要件時，法律效果歸屬於本人", "丙為甲、乙之代理人，其代理甲返還甲對乙之借款，並代理乙收受該筆借款，即丙為雙方代理 之行為，屬違反民法第106條禁止雙方代理之規定", "依民法第103條第1項之規定，代理人於代理權限內，以本人名義所為之意思表示，直接對本 人發生效力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00120', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '關於胎兒權利能力，下列敘述何者錯誤？', '["採概括保護主義，亦即以胎兒活產為條件，就一切法律關係，為胎兒之利益，視為既已出生", "將來如非死產者，自受胎時起，為胎兒之利益，即已取得權利能力，而以死產為其解除條件， 使權利能力溯及消滅", "胎兒須出生，始得為繼承人，並於保留其應繼分後，他繼承人得分割遺產", "若被繼承人遺留之消極財產大於積極財產，因胎兒不繼承該債務，而無待於拋棄繼承"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00121', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲向木雕師傅乙訂製福祿壽三仙木雕 1 座，並告知乙該木雕將作為其母丙 60 大壽之生日賀禮； 孰料丙生日前3天，因乙疏忽未將工作室上鎖，以致丁輕易潛入竊走即將完工之木雕。下列敘述 何者正確？', '["丁竊走福祿壽三仙木雕，以致乙無法如期交付木雕予甲，乃屬不可歸責於己之事由而給付不能， 故乙不負給付之責", "乙無法如期交付福祿壽三仙木雕予甲，乃因其疏忽未將工作室上鎖所致，故屬於可歸責於乙之 給付遲延", "若甲另以高價購得類似木雕並已贈與丙，於丙生日過後1個月，乙透過警察尋回失竊之福祿壽 三仙木雕，旋即趕工完成後交付予甲，此際甲不得拒絕受領，僅得請求因遲延所生損害之賠償", "因甲、乙約定有福祿壽三仙木雕之給付期限，故乙遲延給付時，甲得無條件逕自解除其契約 42050"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00122', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲證券公司高薪聘請乙擔任理財投資協理，並要求乙出具人事保證；乙遂央請其父丙與甲公司訂 立書面人事保證契約。下列敘述何者錯誤？', '["甲、丙間所成立之人事保證契約，主要係為擔保乙將來因職務上之行為而對甲造成損害時，得 由丙代負損害賠償責任", "乙若拋棄其對甲因契約所生之抗辯，該拋棄對於保證人丙不生效力", "甲、丙間所成立之人事保證契約，不得逾3年。逾3年者，縮短為3年，以保護保證人之權益", "甲對於乙職務上行為可能造成之損害，若已參加員工誠實保證保險，則丙即得免除其全部之保 證責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00123', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲以每個月新臺幣5萬元之報酬，僱請乙擔任日班、某固定路線之載送貨物駕駛員。依民法規定， 下列敘述何者錯誤？', '["若甲未經乙之同意，擅自將其對乙之勞務請求權讓與給友人丙，則乙得終止契約", "若甲乙發生衝突，甲於隔日拒絕乙進入公司，則當日始終在公司外圍待命之乙嗣後仍須補服勞 務", "若乙生病須住院治療，因病1年內不能工作，則甲乙間之契約縱定有期限，乙仍得於期限屆滿 前終止", "若甲經常情緒失控，在公司全體員工前恣意辱罵乙，則甲乙間之契約縱定有期限，乙仍得於期 限屆滿前終止，且乙得向甲請求損害賠償"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00124', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲欲向乙借款新臺幣（下同）200 萬元。為取信於乙，甲之兄丙出面與乙約定，若甲屆期不償還 該筆借款，則由丙代負履行責任。下列敘述何者錯誤？', '["若甲乙就該200萬元債務約定之利率為週年30%，則丙得主張乙就超過法定最高利率限制之利 息，無請求權", "若甲乙就該200萬元債務約定之利率為週年10%，則乙丙亦得約定丙僅保證原本，而不保證利 息", "若甲對乙有1筆具抵銷適狀之100萬元債權，則丙得以此主張抵銷", "於乙縱使未就甲之財產強制執行而無效果，則丙均得對乙拒絕清償"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00125', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲為逃避其債權人乙之強制執行，與女友丙通謀虛偽於甲所有之A地設定普通抵押權。下列敘述 何者錯誤？', '["此設定抵押權之物權行為有效", "乙得依民法第242條行使代位權，請求丙塗銷該抵押權之設定登記", "若乙受有損害時，尚得向甲請求損害賠償", "乙得向甲請求回復原狀"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL),
  ('pukao-d592fc58-moex-00126', 'pukao-d592fc58', 'pukao-d592fc58-moex-110-a7c7609b', 'sub-pukao-d592fc58-03', NULL, 'single_choice', '甲乙丙共有A屋，應有部分各為1/3。下列敘述何者錯誤？', '["甲得將其應有部分處分給丁", "乙得將其應有部分設定普通抵押權給戊", "丙得將其應有部分設定普通地上權給己", "甲得將其應有部分出租給庚"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:12+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "420", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "商業行政"}'::jsonb, NULL)
